#include <stdio.h>
#define MAX_EXAMS 100

typedef struct {
    char id[16];
    char name[64];
    int req_wpm;
    float min_accuracy;
} ExamRule;

void printExamDetails(ExamRule exam) {
    printf("Exam: %s\n", exam.name);
    printf("Target Speed: %d WPM\n", exam.req_wpm);
    printf("Threshold: %.2f%%\n", exam.min_accuracy);
}

int main() {
    ExamRule exam1 = {"ssc-chsl", "SSC CHSL", 35, 93.50};
    if (exam1.req_wpm >= 35) {
        printExamDetails(exam1);
    }
    return 0;
}
